namespace UniversityCourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Code { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

public class Instructor
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Bio { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;
}

public class Course
{
    public int Id { get; set; }
    public string Code { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Credits { get; set; }
    public string Schedule { get; set; } = string.Empty;
    public int DepartmentId { get; set; }
    public string DepartmentName { get; set; } = string.Empty;
    public Instructor Instructor { get; set; } = new();
    public bool IsFeatured { get; set; }
}

public class EnrollmentRequest
{
    public string StudentName { get; set; } = string.Empty;
    public string StudentId { get; set; } = string.Empty;
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public interface ICatalogService
{
    List<Department> GetDepartments();
    List<Course> GetAllCourses();
    List<Course> GetFeaturedCourses();
    List<Course> GetCoursesByDepartment(int departmentId);
    Course? GetCourseById(int id);
    List<Course> SearchCourses(string? searchTerm, int? departmentId);
    bool SubmitEnrollmentRequest(EnrollmentRequest request);
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService : ICatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Course> _courses;

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Name = "Computer Science", Code = "CS", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Name = "Mathematics", Code = "MATH", Description = "Study of numbers, structures, and patterns." },
            new() { Id = 3, Name = "Physics", Code = "PHYS", Description = "Study of matter, energy, and the fundamental forces of nature." },
            new() { Id = 4, Name = "English", Code = "ENG", Description = "Study of literature, writing, and language." },
            new() { Id = 5, Name = "History", Code = "HIST", Description = "Study of past events and civilizations." }
        };

        _courses = new List<Course>
        {
            new()
            {
                Id = 1, Code = "CS 101", Title = "Introduction to Programming",
                Description = "Learn the fundamentals of programming using C#. Topics include variables, control flow, functions, and object-oriented design principles.",
                Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true,
                Instructor = new() { Id = 1, Name = "Dr. Sarah Chen", Title = "Associate Professor", Bio = "Dr. Chen has 15 years of experience in software engineering education. She holds a PhD from MIT and has published extensively on programming pedagogy.", Email = "s.chen@university.edu" }
            },
            new()
            {
                Id = 2, Code = "CS 201", Title = "Data Structures and Algorithms",
                Description = "Study of fundamental data structures (arrays, linked lists, trees, graphs) and algorithm design techniques (divide and conquer, dynamic programming, greedy).",
                Credits = 4, Schedule = "Tue/Thu 10:30–11:50 AM", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true,
                Instructor = new() { Id = 2, Name = "Dr. James Rodriguez", Title = "Professor", Bio = "Dr. Rodriguez is a leading researcher in algorithm optimization. He previously worked at Google Research and has authored two textbooks on algorithms.", Email = "j.rodriguez@university.edu" }
            },
            new()
            {
                Id = 3, Code = "CS 310", Title = "Database Systems",
                Description = "Introduction to database design, SQL, normalization, transaction management, and modern NoSQL approaches.",
                Credits = 3, Schedule = "Mon/Wed 2:00–3:20 PM", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = false,
                Instructor = new() { Id = 3, Name = "Dr. Maria Lopez", Title = "Assistant Professor", Bio = "Dr. Lopez specializes in distributed database systems and has industry experience at Amazon Web Services.", Email = "m.lopez@university.edu" }
            },
            new()
            {
                Id = 4, Code = "MATH 101", Title = "Calculus I",
                Description = "Limits, derivatives, and integrals of single-variable functions. Applications to physics and engineering.",
                Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = true,
                Instructor = new() { Id = 4, Name = "Dr. Alan Park", Title = "Professor", Bio = "Dr. Park has been teaching calculus for over 20 years and is known for making abstract concepts accessible to all students.", Email = "a.park@university.edu" }
            },
            new()
            {
                Id = 5, Code = "MATH 201", Title = "Linear Algebra",
                Description = "Vector spaces, matrices, linear transformations, eigenvalues, and applications to data science and computer graphics.",
                Credits = 3, Schedule = "Tue/Thu 1:00–2:20 PM", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = false,
                Instructor = new() { Id = 5, Name = "Dr. Lisa Wang", Title = "Associate Professor", Bio = "Dr. Wang's research focuses on applied linear algebra in machine learning. She consults for several AI startups.", Email = "l.wang@university.edu" }
            },
            new()
            {
                Id = 6, Code = "PHYS 101", Title = "General Physics I",
                Description = "Mechanics, thermodynamics, and waves. Laboratory component included with hands-on experiments.",
                Credits = 4, Schedule = "Mon/Wed/Fri 11:00–11:50 AM + Lab Thu 2:00–4:50 PM", DepartmentId = 3, DepartmentName = "Physics", IsFeatured = true,
                Instructor = new() { Id = 6, Name = "Dr. Robert Kim", Title = "Professor", Bio = "Dr. Kim is an experimental physicist who previously worked at CERN. He brings real-world research examples into the classroom.", Email = "r.kim@university.edu" }
            },
            new()
            {
                Id = 7, Code = "PHYS 220", Title = "Electromagnetism",
                Description = "Electric and magnetic fields, Maxwell's equations, electromagnetic waves, and optics.",
                Credits = 3, Schedule = "Tue/Thu 9:00–10:20 AM", DepartmentId = 3, DepartmentName = "Physics", IsFeatured = false,
                Instructor = new() { Id = 7, Name = "Dr. Emily Foster", Title = "Associate Professor", Bio = "Dr. Foster's research in photonics has led to multiple patents. She emphasizes practical applications of electromagnetic theory.", Email = "e.foster@university.edu" }
            },
            new()
            {
                Id = 8, Code = "ENG 101", Title = "Composition and Rhetoric",
                Description = "Develop critical thinking and writing skills through essay composition, argumentation, and rhetorical analysis.",
                Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", DepartmentId = 4, DepartmentName = "English", IsFeatured = false,
                Instructor = new() { Id = 8, Name = "Prof. Diana Hart", Title = "Senior Lecturer", Bio = "Prof. Hart is an award-winning author who brings her creative writing expertise to first-year composition courses.", Email = "d.hart@university.edu" }
            },
            new()
            {
                Id = 9, Code = "ENG 250", Title = "American Literature",
                Description = "Survey of major American literary works from the colonial period to the present, with emphasis on cultural context.",
                Credits = 3, Schedule = "Tue/Thu 3:00–4:20 PM", DepartmentId = 4, DepartmentName = "English", IsFeatured = false,
                Instructor = new() { Id = 9, Name = "Dr. Thomas Blake", Title = "Professor", Bio = "Dr. Blake is a Pulitzer Prize-nominated critic whose work on 20th-century American fiction is widely cited.", Email = "t.blake@university.edu" }
            },
            new()
            {
                Id = 10, Code = "HIST 101", Title = "World History to 1500",
                Description = "Survey of major civilizations, empires, and cultural developments from prehistory through the late medieval period.",
                Credits = 3, Schedule = "Mon/Wed 10:00–11:20 AM", DepartmentId = 5, DepartmentName = "History", IsFeatured = false,
                Instructor = new() { Id = 10, Name = "Dr. Amara Johnson", Title = "Associate Professor", Bio = "Dr. Johnson is an archaeologist and historian specializing in ancient Mediterranean civilizations. She leads annual field excavations in Greece.", Email = "a.johnson@university.edu" }
            }
        };
    }

    public List<Department> GetDepartments() => _departments;

    public List<Course> GetAllCourses() => _courses;

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public List<Course> GetCoursesByDepartment(int departmentId) =>
        _courses.Where(c => c.DepartmentId == departmentId).ToList();

    public Course? GetCourseById(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> SearchCourses(string? searchTerm, int? departmentId)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue && departmentId.Value > 0)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim().ToLowerInvariant();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Instructor.Name.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public bool SubmitEnrollmentRequest(EnrollmentRequest request)
    {
        return !string.IsNullOrWhiteSpace(request.StudentName)
            && !string.IsNullOrWhiteSpace(request.StudentId)
            && request.CourseId > 0
            && _courses.Any(c => c.Id == request.CourseId);
    }
}

