            },
            new()
            {
                Id = 5, Code = "MATH 201", Title = "Linear Algebra",
                Description = "Vector spaces, matrices, linear transformations, eigenvalues, and applications to data science and computer graphics.",
                Credits = 3, Schedule = "Tue/Thu 1:00–2:20 PM", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = false,
                Instructor = new() { Id = 5, Name = "Dr. Lisa Wang", Title = "Associate Professor", Bio = "Dr. Wang's research focuses on applied linear algebra in machine learning. She consults for several AI startups.", Email = "l.wang@university.edu" }
            },
            new()
            {
                Id = 6, Code = "PHYS 101", Title = "General Physics I",
                Description = "Mechanics, thermodynamics, and waves. Laboratory component included with hands-on experiments.",
                Credits = 4, Schedule = "Mon/Wed/Fri 11:00–11:50 AM + Lab Thu 2:00–4:50 PM", DepartmentId = 3, DepartmentName = "Physics", IsFeatured = true,
                Instructor = new() { Id = 6, Name = "Dr. Robert Kim", Title = "Professor", Bio = "Dr. Kim is an experimental physicist who previously worked at CERN. He brings real-world research examples into the classroom.", Email = "r.kim@university.edu" }
            },
            new()
