@using UniversityCourseCatalog.Models

<div class="course-card">
    <div class="card-header">
        <span class="course-code">@Course.Code</span>
        <span class="credits-badge">@Course.Credits credits</span>
    </div>
    <h4><a href="/courses/@Course.Id">@Course.Title</a></h4>
    <p class="department">@Course.DepartmentName</p>
    <p class="instructor">@Course.Instructor.Name</p>
    <p class="schedule">@Course.Schedule</p>
</div>

@code {
    [Parameter, EditorRequired]
    public Course Course { get; set; } = default!;
}

@using UniversityCourseCatalog.Models

<div class="instructor-bio">
    <h3>Instructor</h3>
    <h4>@Instructor.Name</h4>
    <p class="instructor-title">@Instructor.Title</p>
    <p>@Instructor.Bio</p>
    <p class="instructor-email"><a href="mailto:@Instructor.Email">@Instructor.Email</a></p>
</div>

@code {
    [Parameter, EditorRequired]
    public Instructor Instructor { get; set; } = default!;
}

@using UniversityCourseCatalog.Models

<div class="department-links">
    <h3>Departments</h3>
    <ul>
        @foreach (var dept in Departments)
        {
            <li><a href="/catalog?departmentId=@dept.Id">@dept.Name (@dept.Code)</a></li>
        }
    </ul>
</div>

@code {
    [Parameter, EditorRequired]
    public List<Department> Departments { get; set; } = default!;
}

@using UniversityCourseCatalog.Models

<div class="catalog-filters">
    <div class="filter-row">
        <input type="text" placeholder="Search courses..." value="@SearchTerm"
               @oninput="OnSearchInput" class="search-input" />
        <select value="@SelectedDepartmentId" @onchange="OnDepartmentChange" class="department-select">
            <option value="0">All Departments</option>
            @foreach (var dept in Departments)
            {
                <option value="@dept.Id">@dept.Name</option>
            }
        </select>
    </div>
</div>

@code {
    [Parameter] public string? SearchTerm { get; set; }
    [Parameter] public int SelectedDepartmentId { get; set; }
    [Parameter, EditorRequired] public List<Department> Departments { get; set; } = default!;
    [Parameter] public EventCallback<string> OnSearchChanged { get; set; }
    [Parameter] public EventCallback<int> OnDepartmentChanged { get; set; }

    private async Task OnSearchInput(ChangeEventArgs e)
    {
        await OnSearchChanged.InvokeAsync(e.Value?.ToString() ?? string.Empty);
    }

    private async Task OnDepartmentChange(ChangeEventArgs e)
    {
        if (int.TryParse(e.Value?.ToString(), out var id))
            await OnDepartmentChanged.InvokeAsync(id);
    }
}

