@page "/catalog"
@rendermode InteractiveServer
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Components.Shared
@inject ICatalogService CatalogService

<PageTitle>Course Catalog</PageTitle>

<div class="catalog-page">
    <h1>Course Catalog</h1>

    <CatalogFilters SearchTerm="@_searchTerm"
                    SelectedDepartmentId="@_selectedDepartmentId"
                    Departments="_departments"
                    OnSearchChanged="HandleSearchChanged"
                    OnDepartmentChanged="HandleDepartmentChanged" />

    <CourseList Courses="_filteredCourses" />
</div>

@code {
    private List<Department> _departments = new();
    private List<Course> _filteredCourses = new();
    private string? _searchTerm;
    private int _selectedDepartmentId;

    [SupplyParameterFromQuery]
    public int? DepartmentId { get; set; }

    protected override void OnInitialized()
    {
        _departments = CatalogService.GetDepartments();
        if (DepartmentId.HasValue)
            _selectedDepartmentId = DepartmentId.Value;
        ApplyFilters();
    }

    private void HandleSearchChanged(string searchTerm)
    {
        _searchTerm = searchTerm;
        ApplyFilters();
    }

    private void HandleDepartmentChanged(int departmentId)
    {
        _selectedDepartmentId = departmentId;
        ApplyFilters();
    }

    private void ApplyFilters()
    {
        _filteredCourses = CatalogService.SearchCourses(
            _searchTerm,
            _selectedDepartmentId > 0 ? _selectedDepartmentId : null);
    }
}

@page "/courses/{Id:int}"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Components.Shared
@inject ICatalogService CatalogService

<PageTitle>@(_course?.Title ?? "Course Not Found")</PageTitle>

<div class="course-detail-page">
    @if (_course is null)
    {
        <h1>Course Not Found</h1>
        <p>The requested course does not exist.</p>
        <a href="/catalog">Back to Catalog</a>
    }
    else
    {
        <nav class="breadcrumb">
            <a href="/">Home</a> &gt;
            <a href="/catalog?departmentId=@_course.DepartmentId">@_course.DepartmentName</a> &gt;
            <span>@_course.Code</span>
        </nav>

        <h1>@_course.Code — @_course.Title</h1>

        <div class="course-meta">
            <span class="credits"><strong>Credits:</strong> @_course.Credits</span>
            <span class="schedule"><strong>Schedule:</strong> @_course.Schedule</span>
            <span class="department"><strong>Department:</strong> @_course.DepartmentName</span>
        </div>

        <div class="course-description">
            <h2>Description</h2>
            <p>@_course.Description</p>
        </div>

        <InstructorBio Instructor="_course.Instructor" />

        <div class="enroll-link">
            <a href="/enroll?courseId=@_course.Id" class="btn-primary">Request Enrollment</a>
        </div>
    }
</div>

@code {
    [Parameter]
    public int Id { get; set; }

    private Course? _course;

    protected override void OnInitialized()
    {
        _course = CatalogService.GetCourseById(Id);
    }
}

@page "/enroll"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject ICatalogService CatalogService

<PageTitle>Enrollment Request</PageTitle>

<div class="enroll-page">
    <h1>Enrollment Request</h1>

    @if (_submitted)
    {
        <div class="success-message">
            <h2>Request Submitted</h2>
            <p>Your enrollment request has been submitted successfully. You will receive a confirmation via your university email.</p>
            <a href="/catalog">Back to Catalog</a>
        </div>
    }
    else
    {
        <p>Fill out the form below to request enrollment in a course.</p>

        @if (!string.IsNullOrEmpty(_errorMessage))
        {
            <div class="error-message">@_errorMessage</div>
        }

        <form method="post" @onsubmit="HandleSubmit" @formname="enrollment">
            <AntiforgeryToken />

            <div class="form-group">
                <label for="studentName">Full Name</label>
                <input type="text" id="studentName" name="Model.StudentName"
                       value="@Model.StudentName" required />
            </div>

            <div class="form-group">
                <label for="studentId">Student ID</label>
                <input type="text" id="studentId" name="Model.StudentId"
                       value="@Model.StudentId" required />
            </div>

            <div class="form-group">
                <label for="courseId">Course</label>
                <select id="courseId" name="Model.CourseId" required>
                    <option value="">— Select a course —</option>
                    @foreach (var course in _courses)
                    {
                        <option value="@course.Id" selected="@(course.Id == Model.CourseId)">
                            @course.Code — @course.Title
                        </option>
                    }
                </select>
            </div>

            <button type="submit" class="btn-primary">Submit Request</button>
        </form>
    }
</div>

@code {
    private List<Course> _courses = new();
    private bool _submitted;
    private string? _errorMessage;

    [SupplyParameterFromForm]
    private EnrollmentRequest Model { get; set; } = new();

    [SupplyParameterFromQuery]
    public int? CourseId { get; set; }

    protected override void OnInitialized()
    {
        _courses = CatalogService.GetAllCourses();
        if (CourseId.HasValue && Model.CourseId == 0)
            Model.CourseId = CourseId.Value;
    }

    private void HandleSubmit()
    {
        if (string.IsNullOrWhiteSpace(Model.StudentName) ||
            string.IsNullOrWhiteSpace(Model.StudentId) ||
            Model.CourseId <= 0)
        {
            _errorMessage = "Please fill in all fields.";
            return;
        }

        var success = CatalogService.SubmitEnrollmentRequest(Model);
        if (success)
        {
            _submitted = true;
        }
        else
        {
            _errorMessage = "Unable to process your request. Please verify the selected course and try again.";
        }
    }
}

