toolArgs.new_str:
@page "/"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Components.Shared
@inject ICatalogService CatalogService

<PageTitle>University Course Catalog</PageTitle>

<div class="home-page">
    <div class="hero">
        <h1>University Course Catalog</h1>
        <p>Explore our departments and courses for the upcoming semester.</p>
        <a href="/catalog" class="btn-primary">Browse All Courses</a>
    </div>

    <FeaturedCourses Courses="_featuredCourses" />

    <DepartmentLinks Departments="_departments" />
</div>

@code {
    private List<Course> _featuredCourses = new();
    private List<Department> _departments = new();

    protected override void OnInitialized()
    {
        _featuredCourses = CatalogService.GetFeaturedCourses();
        _departments = CatalogService.GetDepartments();
    }
}

arguments.file_text:
/* Course Card */
.course-card {
    border: 1px solid #e0e0e0;
    border-radius: 8px;
    padding: 1.2rem;
    background: #fff;
    transition: box-shadow 0.2s;
}

.course-card:hover {
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.1);
}

.course-card .card-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 0.5rem;
}

.course-card .course-code {
    font-weight: 600;
    color: #1a5276;
}

.course-card .credits-badge {
    background: #e8f4fd;
    color: #1a5276;
    padding: 0.2rem 0.6rem;
    border-radius: 12px;
    font-size: 0.85rem;
}

.course-card h4 {
    margin: 0.3rem 0;
}

.course-card h4 a {
    color: #2c3e50;
    text-decoration: none;
}

.course-card h4 a:hover {
    color: #1a5276;
    text-decoration: underline;
}

.course-card .department,
.course-card .instructor,
.course-card .schedule {
    margin: 0.2rem 0;
    font-size: 0.9rem;
    color: #555;
}

/* Course Grid */
.course-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(300px, 1fr));
    gap: 1.2rem;
    margin-top: 1rem;
}

/* Home Page */
.home-page .hero {
    text-align: center;
    padding: 3rem 1rem;
    background: linear-gradient(135deg, #1a5276, #2980b9);
    color: #fff;
    border-radius: 8px;
    margin-bottom: 2rem;
}

.home-page .hero h1 {
    font-size: 2.2rem;
    margin-bottom: 0.5rem;
}

.home-page .hero p {
    font-size: 1.1rem;
    margin-bottom: 1.5rem;
    opacity: 0.9;
}

/* Buttons */
.btn-primary {
    display: inline-block;
    background: #2980b9;
    color: #fff;
    padding: 0.7rem 1.5rem;
    border-radius: 6px;
    text-decoration: none;
    border: none;
    font-size: 1rem;
    cursor: pointer;
}

.btn-primary:hover {
    background: #1a5276;
}

/* Department Links */
.department-links {
    margin-top: 2rem;
}

.department-links ul {
    list-style: none;
    padding: 0;
    display: flex;
    flex-wrap: wrap;
    gap: 0.8rem;
}

.department-links li a {
    display: block;
    padding: 0.6rem 1.2rem;
    background: #f0f4f8;
    border-radius: 6px;
    text-decoration: none;
    color: #1a5276;
    font-weight: 500;
}

.department-links li a:hover {
    background: #d6eaf8;
}

/* Catalog Filters */
.catalog-filters {
    margin-bottom: 1.5rem;
}

.filter-row {
    display: flex;
    gap: 1rem;
    flex-wrap: wrap;
}

.search-input {
    flex: 1;
    min-width: 200px;
    padding: 0.6rem 1rem;
    border: 1px solid #ccc;
    border-radius: 6px;
    font-size: 1rem;
}

.department-select {
    padding: 0.6rem 1rem;
    border: 1px solid #ccc;
    border-radius: 6px;
    font-size: 1rem;
    min-width: 180px;
}

/* Course List */
.no-results {
    padding: 2rem;
    text-align: center;
    color: #666;
}

.result-count {
    color: #666;
    margin-bottom: 0.5rem;
}

/* Course Detail */
.course-detail-page .breadcrumb {
    margin-bottom: 1.5rem;
    color: #666;
}

.course-detail-page .breadcrumb a {
    color: #2980b9;
    text-decoration: none;
}

.course-detail-page .breadcrumb a:hover {
    text-decoration: underline;
}

.course-detail-page .course-meta {
    display: flex;
    gap: 2rem;
    flex-wrap: wrap;
    margin: 1.5rem 0;
    padding: 1rem;
    background: #f8f9fa;
    border-radius: 6px;
}

.course-detail-page .course-description {
    margin: 1.5rem 0;
}

.course-detail-page .enroll-link {
    margin-top: 2rem;
}

/* Instructor Bio */
.instructor-bio {
    margin-top: 2rem;
    padding: 1.5rem;
    background: #f0f4f8;
    border-radius: 8px;
}

.instructor-bio .instructor-title {
    color: #555;
    font-style: italic;
}

.instructor-bio .instructor-email a {
    color: #2980b9;
}

/* Enrollment Form */
.enroll-page form {
    max-width: 500px;
}

.form-group {
    margin-bottom: 1.2rem;
}

.form-group label {
    display: block;
    margin-bottom: 0.4rem;
    font-weight: 500;
}

.form-group input,
.form-group select {
    width: 100%;
    padding: 0.6rem 1rem;
    border: 1px solid #ccc;
    border-radius: 6px;
    font-size: 1rem;
}

.success-message {
    padding: 1.5rem;
    background: #d4edda;
    border: 1px solid #c3e6cb;
    border-radius: 8px;
    color: #155724;
}

.error-message {
    padding: 0.8rem 1rem;
    background: #f8d7da;
    border: 1px solid #f5c6cb;
    border-radius: 6px;
    color: #721c24;
    margin-bottom: 1rem;
}

